import React, { useEffect, useState, useRef } from 'react';
import { StyleSheet, View, SafeAreaView, StatusBar, BackHandler, ActivityIndicator, Text, Platform, Alert } from 'react-native';
import { WebView } from 'react-native-webview';
import * as Location from 'expo-location';

export default function App() {
  const [locationPermission, setLocationPermission] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const webViewRef = useRef(null);
  const TARGET_URL = 'https://ais-pre-uukjq5zko7dnaqj35uhokr-583460041327.europe-west1.run.app';

  // طلب صلاحيات الموقع لتمريرها تلقائياً للويب فيو
  useEffect(() => {
    (async () => {
      let { status } = await Location.requestForegroundPermissionsAsync();
      setLocationPermission(status === 'granted');
    })();
  }, []);

  // معالجة زر الرجوع في هواتف الأندرويد لعدم الخروج المفاجئ من التطبيق
  useEffect(() => {
    const onBackPress = () => {
      if (webViewRef.current) {
        webViewRef.current.goBack();
        return true;
      }
      return false;
    };

    BackHandler.addEventListener('hardwareBackPress', onBackPress);
    return () => BackHandler.removeEventListener('hardwareBackPress', onBackPress);
  }, []);

  return (
    <SafeAreaView style={styles.container}>
      <StatusBar backgroundColor="#ef4444" barStyle="light-content" />
      <View style={styles.innerContainer}>
        <WebView
          ref={webViewRef}
          source={{ uri: TARGET_URL }}
          style={styles.webview}
          javaScriptEnabled={true}
          domStorageEnabled={true}
          startInLoadingState={true}
          geolocationEnabled={true}
          originWhitelist={['*']}
          scalesPageToFit={true}
          onLoadStart={() => setIsLoading(true)}
          onLoadEnd={() => setIsLoading(false)}
          onError={(syntheticEvent) => {
            const { nativeEvent } = syntheticEvent;
            console.warn('WebView error: ', nativeEvent);
            Alert.alert(
              'خطأ في الاتصال',
              'يرجى التأكد من اتصالك بالإنترنت والمحاولة مجدداً لفتح طلبات فرشوط.',
              [{ text: 'تحديث', onPress: () => webViewRef.current?.reload() }]
            );
          }}
        />
        {isLoading && (
          <View style={styles.loadingContainer}>
            <ActivityIndicator size="large" color="#ef4444" />
            <Text style={styles.loadingText}>جاري تحميل طلبات فرشوط بفرشوط...</Text>
          </View>
        )}
      </View>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#ef4444',
  },
  innerContainer: {
    flex: 1,
    position: 'relative',
  },
  webview: {
    flex: 1,
  },
  loadingContainer: {
    position: 'absolute',
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
    backgroundColor: '#ffffff',
    justifyContent: 'center',
    alignItems: 'center',
  },
  loadingText: {
    marginTop: 10,
    fontSize: 14,
    fontWeight: 'bold',
    color: '#334155',
  },
});
